const readline = require('readline');

function main() {
    const rl = readline.createInterface({
        input: process.stdin,
        output: process.stdout
    });

    let inputLines = [];

    rl.on('line', (line) => {
        inputLines.push(line);
        if (inputLines.length === 2) {
            rl.close();
        }
    });

    rl.on('close', () => {
        // Extract the number of elements and the integer k
        let [n, k] = inputLines[0].split(' ').map(Number);
        let array = inputLines[1].split(' ').map(Number);

        let minDifference = Infinity;
        let result = Infinity;

        // Iterate through the array to find the element with the smallest difference from k
        for (let num of array) {
            let difference = Math.abs(num - k);
            if (difference < minDifference || (difference === minDifference && num < result)) {
                minDifference = difference;
                result = num;
            }
        }

        // Print the result
        console.log(result);
    });
}

